INSERT INTO `management_areas` VALUES ('014c08b1-283f-4c19-ae51-1f3a1d890cfd','INC-KOMATI','Komati','Incomati',1,'South Africa / Eswatini / Mozambique','Komati River subcatchment. The main tributary of the Incomati, rising in the Mpumalanga highlands and flowing through Eswatini before re-entering South Africa at Komatipoort, then Mozambique. Maguga and Driekoppies dams are the primary storage infrastructure.'),('18618644-b59d-42dd-84c5-78214ab3f68d','MAP-NGWEMPISI','Ngwempisi','Maputo',1,'South Africa / Eswatini','Ngwempisi River subcatchment in Eswatini. Right-bank tributary of the Usuthu.'),('2a3720ca-9383-4766-ab68-f4b7adb0cee9','MAP-LUSUSHWANA','Lusushwana','Maputo',1,'Eswatini','Lusushwana River subcatchment in western Eswatini. Left-bank tributary of the Usuthu.'),('331c686a-e8db-45e2-ba41-a469f6af7573','MAP-MPULUZI','Mpuluzi','Maputo',1,'South Africa / Eswatini','Mpuluzi River subcatchment straddling the RSA–Eswatini border. Tributary of the Usuthu.'),('38bd8ea0-067a-4018-864e-f6af4c595809','MAP-MAPUTO','Lower Maputo','Maputo',1,'Mozambique','Lower Maputo River mainstem in Mozambique. Receives the Usuthu and flows to Maputo Bay. The compliance gauge is E-4 at Salamanga.'),('45a3ce17-659a-4be5-a3a2-8fdba3dfab3c','MAP-MKHONDVO','Mkhondvo','Maputo',1,'South Africa / Eswatini','Mkhondvo River subcatchment straddling the RSA–Eswatini border. Left-bank tributary of the Usuthu.'),('54e45afd-3450-463c-acf9-daf2e98d0d89','MAP-NGWAVUMA','Ngwavuma','Maputo',1,'South Africa / Eswatini / Mozambique','Ngwavuma River subcatchment. Flows from the RSA highlands through Eswatini into Mozambique, joining the Usuthu before the Maputo confluence.'),('7e82e206-a806-4a92-9c11-79936646b06e','INC-SABIE','Sabie','Incomati',1,'South Africa / Mozambique','Sabie River subcatchment. Rises near Sabie town in Mpumalanga, flows through the Kruger NP, crosses into Mozambique at Gaza Province and joins the Incomati. Important for ecology in the TFCA.'),('8183b3e6-6920-4ba3-ad8f-d8fb6e370a69','MAP-PONGOLA','Pongola','Maputo',1,'South Africa / Mozambique','Pongola River subcatchment in KwaZulu-Natal (RSA) and Mozambique. Pongolapoort (Jozini) Dam is the primary storage. Joins the Usuthu at Ndumo.'),('8e5a9b9d-b713-4422-b7de-7b71fbf6a040','MAP-USUTHU','Usuthu','Maputo',1,'South Africa / Eswatini / Mozambique','Usuthu (Lusutfu) River mainstem subcatchment. Largest tributary of the Maputo River system, flowing through Eswatini and entering Mozambique before joining the Maputo. GS-16 (Big Bend) is the key IIMA compliance gauge.'),('ab7c734f-db53-43c9-9a78-159773893308','INC-CROCODILE','Crocodile','Incomati',1,'South Africa / Mozambique','Crocodile River subcatchment (RSA). Drains the southern slopes of the Mpumalanga escarpment through the Kruger National Park before confluencing with the Incomati at Komatipoort.'),('b63c5b20-380a-4e62-9386-fa205f183d75','INC-UANETZE','Uanetze','Incomati',1,'Mozambique','Uanetze subcatchment in Mozambique. Left-bank tributary of the lower Incomati.'),('bb5315f4-161d-4c29-88c3-a3972b0990cb','INC-MASSINTONTO','Massintonto','Incomati',1,'Mozambique','Massintonto subcatchment in Mozambique. A right-bank tributary joining the lower Incomati.'),('c855c244-ddb9-4d7f-987a-53fd1546800f','INC-LOWER','Lower Incomati','Incomati',1,'Mozambique','Lower Incomati mainstem in Mozambique from Ressano Garcia to the Indian Ocean. Includes the Incomati mouth near Xai-Xai. Critical eflow compliance zone (E-23 / X2H036).'),('db1f7cfb-1466-48b4-94a3-8645c0d71e09','INC-MAZIMECHOPES','Mazimechopes','Incomati',1,'Mozambique','Mazimechopes subcatchment in lower Mozambique. Drains into the coastal zone of the Incomati.');
/*!40000 ALTER TABLE `management_areas` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `measurements`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `measurements` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `station_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `measurement_type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `parameter_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fsc` double DEFAULT NULL,
  `value` double NOT NULL,
  `unit` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `date` timestamp NOT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `submitted_by_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `submitted_at` timestamp NOT NULL,
  `reviewed_by_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reviewed_at` timestamp NULL DEFAULT NULL,
  `review_notes` text COLLATE utf8mb4_unicode_ci,
  `is_self_override` tinyint(1) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `measurements_station_id_foreign` (`station_id`),
  KEY `measurements_parameter_id_foreign` (`parameter_id`),
  KEY `measurements_submitted_by_id_foreign` (`submitted_by_id`),
  KEY `measurements_reviewed_by_id_foreign` (`reviewed_by_id`),
  CONSTRAINT `measurements_parameter_id_foreign` FOREIGN KEY (`parameter_id`) REFERENCES `water_quality_parameters` (`id`),
  CONSTRAINT `measurements_reviewed_by_id_foreign` FOREIGN KEY (`reviewed_by_id`) REFERENCES `users` (`id`),
  CONSTRAINT `measurements_station_id_foreign` FOREIGN KEY (`station_id`) REFERENCES `stations` (`id`),
  CONSTRAINT `measurements_submitted_by_id_foreign` FOREIGN KEY (`submitted_by_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `measurements` WRITE;
/*!40000 ALTER TABLE `measurements` DISABLE KEYS */;
