/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `water_abstractions` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `subcatchment_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `country` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_category` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `period_year` int NOT NULL,
  `period_month` int DEFAULT NULL,
  `volume_mm3` double NOT NULL,
  `data_source` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_estimate` tinyint(1) NOT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `submitted_by_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `submitted_at` timestamp NOT NULL,
  `reviewed_by_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reviewed_at` timestamp NULL DEFAULT NULL,
  `review_notes` text COLLATE utf8mb4_unicode_ci,
  `is_self_override` tinyint(1) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `water_abstractions_subcatchment_id_foreign` (`subcatchment_id`),
  KEY `water_abstractions_user_category_foreign` (`user_category`),
  KEY `water_abstractions_submitted_by_id_foreign` (`submitted_by_id`),
  KEY `water_abstractions_reviewed_by_id_foreign` (`reviewed_by_id`),
  CONSTRAINT `water_abstractions_reviewed_by_id_foreign` FOREIGN KEY (`reviewed_by_id`) REFERENCES `users` (`id`),
  CONSTRAINT `water_abstractions_subcatchment_id_foreign` FOREIGN KEY (`subcatchment_id`) REFERENCES `management_areas` (`id`),
  CONSTRAINT `water_abstractions_submitted_by_id_foreign` FOREIGN KEY (`submitted_by_id`) REFERENCES `users` (`id`),
  CONSTRAINT `water_abstractions_user_category_foreign` FOREIGN KEY (`user_category`) REFERENCES `iima_user_categories` (`code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
